// inferred-not-tested:滚轮缩放非默认,须手动在父视口挂 wheel→zoomWithWheel(上游 d.ts 明示此用法)
import Panzoom from 'https://cdn.jsdelivr.net/npm/@panzoom/panzoom@4.6.2/+esm';
const viewport = document.getElementById('pz'); viewport.style.height = '400px'; viewport.style.overflow = 'hidden';
const content = document.createElement('div'); content.innerHTML = data.content ?? ''; viewport.appendChild(content);
const pz = Panzoom(content, data.options ?? {});
viewport.addEventListener('wheel', pz.zoomWithWheel);

